Bash(powershell -Command "
Add-Type -AssemblyName System.Drawing
@\('Assets/Sprites/Background/stage_1.png','Assets/Sprites/Enemy/B_1_NM.png','Assets/Sprites/Enemy/M_1_Runner.png','Assets/Sprites/Enemy/M_2_Leader.png','Assets/Sprites/Enemy/M_3_Shooter.png','Assets/Sprites/Character/character \(1\).png','Assets/Sprites/Character/character \(2\).png','Assets/Sprites/Object/Barricade_1.png'\) | ForEach-Object {
    try {
        \\$img = [System.Drawing.Image]::FromFile\(\(Resolve-Path \\$_\).Path\)
        '{0,-30} {1} x {2}' -f \(Split-Path \\$_ -Leaf\), \\$img.Width, \\$img.Height
        \\$img.Dispose\(\)
    } catch { '{0,-30} ERROR' -f \\$_ }
}")
